/**
 * AI Script Generator Service Tests  (node environment)
 *
 * Testa o AIScriptGeneratorService:
 *   - generate() happy path via AI
 *   - generate() template fallback quando AI falha
 *   - Template fallback desligado em prod (re-throws)
 *   - generateFromContent() happy path
 *   - generateFromContent() rate-limit error
 *   - generateFromContent() timeout error
 *   - Template structure e compliance notes
 */

// ─── Mocks ───────────────────────────────────────────────────────────────────

jest.mock('@/lib/logger', () => ({
  logger: {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
  },
}));

const mockGenerateJSON = jest.fn();
const mockChatCompletion = jest.fn();

jest.mock('@/lib/ai/groq-client', () => ({
  generateJSON: (...args: unknown[]) => mockGenerateJSON(...args),
  chatCompletion: (...args: unknown[]) => mockChatCompletion(...args),
}));

// ─── Imports ─────────────────────────────────────────────────────────────────

import {
  AIScriptGeneratorService,
  ScriptGenerationParams,
  ContentScriptParams,
  GeneratedScript,
} from '@/lib/ai/script-generator.service';

// ─── Helpers ─────────────────────────────────────────────────────────────────

const sampleAIResult: GeneratedScript = {
  title: 'Treinamento NR-10',
  total_duration: 15,
  scenes: [
    {
      id: 'scene-1',
      title: 'Introdução à NR-10',
      content: 'Neste módulo vamos aprender sobre segurança elétrica...',
      duration: 5,
      avatar_instructions: 'Postura profissional',
      visual_cues: ['Slide inicial'],
      safety_highlights: ['Use EPI adequado'],
    },
    {
      id: 'scene-2',
      title: 'Procedimentos',
      content: 'É fundamental seguir os procedimentos...',
      duration: 5,
      avatar_instructions: 'Enfatizar pontos com as mãos',
      visual_cues: ['Diagrama de procedimentos'],
      safety_highlights: ['Lockout/Tagout'],
    },
    {
      id: 'scene-3',
      title: 'Conclusão',
      content: 'Agora que conhecemos os riscos...',
      duration: 5,
      avatar_instructions: 'Sorriso profissional, encerramento',
      visual_cues: ['Resumo dos tópicos'],
      safety_highlights: ['Meta zero acidentes'],
    },
  ],
  compliance_notes: ['Conforme NR-10 revisão 2024'],
  engagement_tips: ['Quiz prático ao final'],
};

function sampleParams(overrides: Partial<ScriptGenerationParams> = {}): ScriptGenerationParams {
  return {
    nr: 'NR-10',
    topics: ['Segurança em instalações elétricas', 'Procedimentos de emergência'],
    duration: 15,
    audience: 'Operadores de campo',
    company_context: 'Indústria metalúrgica',
    ...overrides,
  };
}

function sampleContentParams(overrides: Partial<ContentScriptParams> = {}): ContentScriptParams {
  return {
    slides: [
      { index: 0, text: 'Bem-vindos ao treinamento' },
      { index: 1, text: 'Procedimentos de segurança' },
    ],
    goal: 'Treinamento de NR-10',
    language: 'pt-BR',
    voiceTone: 'profissional',
    simplificationLevel: 'original',
    duration: 10,
    ...overrides,
  };
}

// ─── Tests ───────────────────────────────────────────────────────────────────

describe('AIScriptGeneratorService', () => {
  const originalEnv = { ...process.env };

  beforeEach(() => {
    jest.clearAllMocks();
    process.env.NODE_ENV = 'test';
    process.env.AI_TEMPLATE_FALLBACK_ENABLED = 'true';
  });

  afterEach(() => {
    process.env.NODE_ENV = originalEnv.NODE_ENV;
    process.env.AI_TEMPLATE_FALLBACK_ENABLED = originalEnv.AI_TEMPLATE_FALLBACK_ENABLED;
  });

  // ════════════════════════════════════════════════════════════════════════════
  // generate() — AI Happy Path
  // ════════════════════════════════════════════════════════════════════════════

  describe('generate() — AI path', () => {
    it('should call generateJSON with system + user prompt', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      const params = sampleParams();
      await AIScriptGeneratorService.generate(params);

      expect(mockGenerateJSON).toHaveBeenCalledTimes(1);
      expect(mockGenerateJSON).toHaveBeenCalledWith(
        expect.stringContaining('Segurança do Trabalho'),
        expect.stringContaining('NR-10'),
        expect.objectContaining({ temperature: 0.7, max_tokens: 4096 })
      );
    });

    it('should return the AI-generated script', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      const result = await AIScriptGeneratorService.generate(sampleParams());

      expect(result.title).toBe('Treinamento NR-10');
      expect(result.scenes).toHaveLength(3);
      expect(result.total_duration).toBe(15);
    });

    it('should include audience in system prompt', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      await AIScriptGeneratorService.generate(
        sampleParams({ audience: 'Gestores de EHS' })
      );

      const systemPrompt = mockGenerateJSON.mock.calls[0][0] as string;
      expect(systemPrompt).toContain('Gestores de EHS');
    });

    it('should include company_context in system prompt', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      await AIScriptGeneratorService.generate(
        sampleParams({ company_context: 'Mineração de ouro' })
      );

      const systemPrompt = mockGenerateJSON.mock.calls[0][0] as string;
      expect(systemPrompt).toContain('Mineração de ouro');
    });

    it('should include topics in user prompt', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      await AIScriptGeneratorService.generate(
        sampleParams({ topics: ['EPI', 'CIPA'] })
      );

      const userPrompt = mockGenerateJSON.mock.calls[0][1] as string;
      expect(userPrompt).toContain('EPI');
      expect(userPrompt).toContain('CIPA');
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // generate() — Template Fallback
  // ════════════════════════════════════════════════════════════════════════════

  describe('generate() — Template fallback', () => {
    it('should fall back to template when AI fails and fallback is enabled', async () => {
      mockGenerateJSON.mockRejectedValueOnce(new Error('API key invalid'));
      process.env.AI_TEMPLATE_FALLBACK_ENABLED = 'true';

      const result = await AIScriptGeneratorService.generate(sampleParams());

      expect(result.title).toContain('NR-10');
      expect(result.scenes.length).toBeGreaterThan(0);
    });

    it('should rethrow in production when AI fails', async () => {
      mockGenerateJSON.mockRejectedValueOnce(new Error('API key invalid'));
      process.env.NODE_ENV = 'production';

      await expect(
        AIScriptGeneratorService.generate(sampleParams())
      ).rejects.toThrow('API key invalid');
    });

    it('should rethrow when fallback is disabled', async () => {
      mockGenerateJSON.mockRejectedValueOnce(new Error('API error'));
      process.env.AI_TEMPLATE_FALLBACK_ENABLED = 'false';

      await expect(
        AIScriptGeneratorService.generate(sampleParams())
      ).rejects.toThrow('API error');
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // Template Structure Validation
  // ════════════════════════════════════════════════════════════════════════════

  describe('Template structure', () => {
    beforeEach(() => {
      mockGenerateJSON.mockRejectedValue(new Error('force fallback'));
      process.env.AI_TEMPLATE_FALLBACK_ENABLED = 'true';
    });

    it('should include intro scene', async () => {
      const result = await AIScriptGeneratorService.generate(sampleParams());

      const intro = result.scenes.find((s) => s.id === 'scene-intro');
      expect(intro).toBeDefined();
      expect(intro!.title).toContain('Introdução');
    });

    it('should create one scene per topic', async () => {
      const topics = ['Risco elétrico', 'EPI', 'Sinalização'];
      const result = await AIScriptGeneratorService.generate(
        sampleParams({ topics })
      );

      // 3 topic scenes + 1 intro = 4
      expect(result.scenes.length).toBe(4);
    });

    it('should use "direto e prático" tone for operadores', async () => {
      const result = await AIScriptGeneratorService.generate(
        sampleParams({ audience: 'Operadores de máquinas' })
      );

      const topicScene = result.scenes.find((s) => s.id !== 'scene-intro');
      expect(topicScene!.content).toContain('direto e prático');
    });

    it('should use "técnico e gerencial" tone for non-operadores', async () => {
      const result = await AIScriptGeneratorService.generate(
        sampleParams({ audience: 'Engenheiros de segurança' })
      );

      const topicScene = result.scenes.find((s) => s.id !== 'scene-intro');
      expect(topicScene!.content).toContain('técnico e gerencial');
    });

    it('should include compliance_notes with NR reference', async () => {
      const result = await AIScriptGeneratorService.generate(sampleParams());

      expect(result.compliance_notes).toEqual(
        expect.arrayContaining([expect.stringContaining('NR-10')])
      );
    });

    it('should include engagement_tips', async () => {
      const result = await AIScriptGeneratorService.generate(sampleParams());

      expect(result.engagement_tips.length).toBeGreaterThan(0);
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // generateFromContent()
  // ════════════════════════════════════════════════════════════════════════════

  describe('generateFromContent()', () => {
    it('should pass slide content in user prompt', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      await AIScriptGeneratorService.generateFromContent(sampleContentParams());

      const userPrompt = mockGenerateJSON.mock.calls[0][1] as string;
      expect(userPrompt).toContain('Bem-vindos ao treinamento');
      expect(userPrompt).toContain('Procedimentos de segurança');
    });

    it('should include language in system prompt', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      await AIScriptGeneratorService.generateFromContent(
        sampleContentParams({ language: 'en-US' })
      );

      const systemPrompt = mockGenerateJSON.mock.calls[0][0] as string;
      expect(systemPrompt).toContain('inglês americano');
    });

    it('should include voice tone in system prompt', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      await AIScriptGeneratorService.generateFromContent(
        sampleContentParams({ voiceTone: 'casual' })
      );

      const systemPrompt = mockGenerateJSON.mock.calls[0][0] as string;
      expect(systemPrompt).toContain('informal, amigável');
    });

    it('should include simplification level in system prompt', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      await AIScriptGeneratorService.generateFromContent(
        sampleContentParams({ simplificationLevel: 'resumir' })
      );

      const systemPrompt = mockGenerateJSON.mock.calls[0][0] as string;
      expect(systemPrompt).toContain('Resuma o conteúdo');
    });

    it('should return AI-generated result', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      const result = await AIScriptGeneratorService.generateFromContent(
        sampleContentParams()
      );

      expect(result.title).toBe('Treinamento NR-10');
      expect(result.scenes).toHaveLength(3);
    });

    it('should include goal in system prompt when provided', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      await AIScriptGeneratorService.generateFromContent(
        sampleContentParams({ goal: 'Onboarding de novos funcionários' })
      );

      const systemPrompt = mockGenerateJSON.mock.calls[0][0] as string;
      expect(systemPrompt).toContain('Onboarding de novos funcionários');
    });

    it('should generate user prompt without slides when none provided', async () => {
      mockGenerateJSON.mockResolvedValueOnce(sampleAIResult);

      await AIScriptGeneratorService.generateFromContent(
        sampleContentParams({ slides: undefined, goal: 'Apresentação institucional' })
      );

      const userPrompt = mockGenerateJSON.mock.calls[0][1] as string;
      expect(userPrompt).toContain('institucional');
      expect(userPrompt).not.toContain('Slide 1');
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // generateFromContent() — Error Handling
  // ════════════════════════════════════════════════════════════════════════════

  describe('generateFromContent() — Error Handling', () => {
    it('should throw user-friendly message on rate limit (429)', async () => {
      mockGenerateJSON.mockRejectedValueOnce(
        new Error('Error 429: rate limit exceeded')
      );

      await expect(
        AIScriptGeneratorService.generateFromContent(sampleContentParams())
      ).rejects.toThrow('Limite de requisições atingido');
    });

    it('should throw user-friendly message on quota exceeded', async () => {
      mockGenerateJSON.mockRejectedValueOnce(
        new Error('quota exceeded for model')
      );

      await expect(
        AIScriptGeneratorService.generateFromContent(sampleContentParams())
      ).rejects.toThrow('Limite de requisições atingido');
    });

    it('should throw user-friendly message on timeout', async () => {
      mockGenerateJSON.mockRejectedValueOnce(
        new Error('Request timed out after 30000ms')
      );

      await expect(
        AIScriptGeneratorService.generateFromContent(sampleContentParams())
      ).rejects.toThrow('geração excedeu o tempo limite');
    });

    it('should throw user-friendly message on abort', async () => {
      mockGenerateJSON.mockRejectedValueOnce(
        new Error('The operation was aborted')
      );

      await expect(
        AIScriptGeneratorService.generateFromContent(sampleContentParams())
      ).rejects.toThrow('geração excedeu o tempo limite');
    });

    it('should rethrow unknown errors without transformation', async () => {
      mockGenerateJSON.mockRejectedValueOnce(
        new Error('Unexpected token in JSON')
      );

      await expect(
        AIScriptGeneratorService.generateFromContent(sampleContentParams())
      ).rejects.toThrow('Unexpected token in JSON');
    });
  });
});
